static uint8_t s_ui_lang = LANG_EN;
void    i18nSetLang(uint8_t l) { s_ui_lang = (l < LANG_COUNT) ? l : LANG_EN; }
uint8_t i18nGetLang() { return s_ui_lang; }

// Translation table, keyed by the English source string. The `tr[]` column order
// matches UiLang; index 0 (English) is unused because the key IS the English. A
// null cell falls back to English. Identical-in-every-language terms (Wi-Fi,
// Bluetooth, GPS, …) are simply omitted — TR() returns the key for those.
//
// Machine-seeded as a first pass — native review welcome; edit cells freely. Add
// rows as more of the UI is wrapped in TR(); a string never in the table just
// renders in English. Lookup is linear (labels build on screen-open, not per
// frame), so order does not matter and you can append anywhere.
struct I18nEntry { const char* en; const char* tr[LANG_COUNT]; };

